     2→import type { ButtonVariant, ButtonSize } from "../../types/ui";
     3→import { cn } from "../../lib/utils";
     4→
     5→interface Props {
     6→  variant?: ButtonVariant;
     7→  size?: ButtonSize;
     8→  href?: string;
     9→  class?: string;
    10→  [key: string]: unknown;
    11→}
    12→
    13→const { variant = "primary", size = "md", href, class: className, ...rest } = Astro.props;
    14→
    15→const baseStyles = "inline-flex items-center justify-center font-medium rounded-lg transition-all duration-normal focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-sakura-500 focus-visible:ring-offset-2 disabled:opacity-50 disabled:cursor-not-allowed";
    16→
    17→const variants: Record<ButtonVariant, string> = {
    18→  primary: "bg-sakura-500 text-white hover:bg-sakura-600 active:bg-sakura-700",
    19→  secondary: "bg-neutral-100 text-neutral-800 hover:bg-neutral-200 active:bg-neutral-300",
    20→  outline: "border-2 border-sakura-500 text-sakura-600 hover:bg-sakura-50 active:bg-sakura-100",
    21→};
    22→
    23→const sizes: Record<ButtonSize, string> = {
    24→  sm: "px-3 py-1.5 text-sm min-h-[36px]",
    25→  md: "px-5 py-2.5 text-base min-h-[44px]",
    26→  lg: "px-7 py-3 text-lg min-h-[52px]",
    27→};
    28→
    29→const classes = cn(baseStyles, variants[variant], sizes[size], className);
    30→
    31→const Tag = href ? "a" : "button";
    32→---
    33→
    34→{href ? (
    35→  <a href={href} class={classes} {...rest}>
    36→    <slot />
    37→  </a>
    38→) : (
    39→  <button class={classes} {...rest}>
    40→    <slot />
    41→  </button>
    42→)}
    43→

