---
import BaseLayout from "../layouts/BaseLayout.astro";
import Header from "../components/common/Header.astro";
import Footer from "../components/common/Footer.astro";
import Hero from "../components/sections/Hero.astro";
import ServiceCards from "../components/sections/ServiceCards.astro";
import CTASection from "../components/sections/CTASection.astro";
import Button from "../components/ui/Button.astro";
import { SITE_CONFIG } from "../lib/constants";
---

<BaseLayout
  title={`${SITE_CONFIG.name} | 仕事と介護の両立支援`}
  description={SITE_CONFIG.description}
>
  <Header transparent />

  {/* Hero Section */}
  <Hero
    title="仕事と介護の両立を、あなたのそばで支えます"
    subtitle="産業ケアマネージャーとして、企業と従業員の両方をサポート。介護離職を防ぎ、安心して働き続けられる環境づくりをお手伝いします。"
    showScrollIndicator={true}
    scrollTargetId="services"
  >
    <div class="flex flex-col sm:flex-row gap-4 justify-center mt-8">
      <Button href="/contact" size="lg" variant="primary">
        無料相談する
      </Button>
      <Button href="/services" size="lg" variant="outline" class="border-white text-white hover:bg-white/10">
        サービスを見る
      </Button>
    </div>
  </Hero>

  {/* Services Section */}
  <ServiceCards />

  {/* CTA Section */}
  <CTASection
    heading="まずはお気軽にご相談ください"
    description="介護に関するお悩みや、サービスについてのご質問など、LINEでお気軽にお問い合わせください。専門スタッフが丁寧にお答えします。"
  />

  <Footer />
</BaseLayout>
